const d = items[0].json;

const s = d.strategy ?? {};
const ig = d.instagram ?? {};
const tw = d.twitter ?? {};
const tt = d.tiktok ?? {};

const tweetThread = Array.isArray(tw.tweets) ? tw.tweets.join('\n\n') : (tw.tweets ?? '');
const onScreen = Array.isArray(tt.onScreenTexts) ? tt.onScreenTexts.join(' | ') : '';

const base = {
  Week: d.week ?? '',
  WeekStart: d.weekStart ?? '',
  CycleWeek: s.cycleWeek ?? '',
  CycleName: s.cycleName ?? '',
  Topic: s.topic ?? '',
  PsychAngle: s.psychologicalAngle ?? '',
  TargetAudience: s.targetAudience ?? '',
  Objective: s.conversionObjective ?? '',
  WhyThisWeek: s.whyThisWeek ?? '',
  Status: 'pending',
  Notes: ''
};

return [
  {
    json: {
      ...base,
      Platform: 'instagram',
      Content: ig.caption ?? '',
      Hashtags: ig.hashtags ?? '',
      ImageCopy: ig.imageCopy ?? '',
      ImagePrompt: ig.imagePrompt ?? '',
      VideoPrompt: '',
      OnScreenTexts: '',
      BestDay: 'Lunes / Viernes',
      BestTime: '9:00am'
    }
  },
  {
    json: {
      ...base,
      Platform: 'twitter',
      Content: tweetThread,
      Hashtags: '',
      ImageCopy: '',
      ImagePrompt: '',
      VideoPrompt: '',
      OnScreenTexts: '',
      BestDay: 'Martes / Jueves',
      BestTime: '8:00am'
    }
  },
  {
    json: {
      ...base,
      Platform: 'tiktok',
      Content: tt.script ?? '',
      Hashtags: '',
      ImageCopy: '',
      ImagePrompt: '',
      VideoPrompt: tt.videoPrompt ?? '',
      OnScreenTexts: onScreen,
      BestDay: 'Miércoles / Sábado',
      BestTime: '6:00pm'
    }
  }
];

